external_knowledge:
- "in a certain way" refers to component names starting with "Component";
- "packaged in a particular method" refers to package names starting with "PDIP";
- "specific test condition" refers to conditions named "Room Temperature%";
- "higher resistance to heat" means thermal resistance values greater than 50.0;
- "when and where this information was recorded" refers to the date and source of the data measurement.

sql:
SELECT AVG(thermal_resistance) AS average_thermal_resistance
FROM component_versions
WHERE date_measured BETWEEN '2023-10-01' AND '2023-10-02';

SELECT DISTINCT package_type_id
FROM components
ORDER BY package_type_id;

SELECT AVG(thermal_resistance) AS average_thermal_resistance
FROM components
WHERE component_id = 1;

SELECT AVG(thermal_resistance) AS average_thermal_resistance, package_type_id
FROM components
GROUP BY package_type_id;

SELECT c.component_name, MIN(c.thermal_resistance) AS min_thermal_resistance
FROM components c
GROUP BY c.component_id;

SELECT MIN(thermal_resistance) AS min_thermal_resistance
FROM component_versions
WHERE date_measured BETWEEN '2023-10-01' AND '2023-10-31';
